import sys

def drop_cap(s: str) -> str:
    chars = list(s)
    i = 0
    n = len(chars)
    while i < n:
        while i < n and chars[i] == ' ':
            i += 1
        start = i
        while i < n and chars[i] != ' ':
            i += 1
        length = i - start
        if length > 2:
            chars[start] = chars[start].upper()
            for j in range(start + 1, i):
                chars[j] = chars[j].lower()
    return ''.join(chars)

def main():
    line = sys.stdin.readline()
    if line.endswith('\n'):
        line = line[:-1]
    print(drop_cap(line))

if __name__ == "__main__":
    main()

import sys

def decompose_number(n: int) -> str:
    if n == 0:
        return ""
    s = str(n)
    L = len(s)
    parts = []
    for i, ch in enumerate(s):
        d = int(ch)
        if d == 0:
            continue
        power = 10 ** (L - i - 1)
        if power == 1:
            parts.append(str(d))
        else:
            parts.append(f"{d}*{power}")
    return "+".join(parts)

def main():
    data = sys.stdin.read().strip()
    if not data:
        return
    n = int(data)
    result = decompose_number(n)
    print(result)

