def solve():
    s = sys.stdin.readline().rstrip('\n')
    n = len(s)
    remove = [False] * n

    for i, ch in enumerate(s):
        if ch == '*':
            remove[i] = True
            if i > 0:
                remove[i - 1] = True
            if i + 1 < n:
                remove[i + 1] = True

    left_power = {'w': 4, 'p': 3, 'b': 2, 's': 1}
