import math

def is_prime(x: int) -> bool:
    if x < 2:
        return False
    if x == 2:
        return True
    if x % 2 == 0:
        return False
    r = int(math.isqrt(x))
    for i in range(3, r + 1, 2):
        if x % i == 0:
            return False
    return True

def is_mersenne_prime(n: int) -> bool:
    if not is_prime(n):
        return False
    if n == 2:
        return True
    M = (1 << n) - 1
    s = 4
    for _ in range(n - 2):
        s = (s * s - 2) % M
    return s == 0

