import ast

def count_change(amount: int, coins):
    """Return the number of ways to make `amount` using unlimited `coins`."""
    dp = [0] * (amount + 1)
    dp[0] = 1
    for c in coins:
        if c <= amount:
            for i in range(c, amount + 1):
                dp[i] += dp[i - c]
    return dp[amount]

def parse_coins(line):
    """
    Parse a line that may look like '[1, 2]', '1 2', '1,2' or even be a list/tuple/int.
    Returns a list of integers.
    """
    # If already an iterable of numbers (list/tuple), just convert to list of int
    if isinstance(line, (list, tuple)):
        return [int(x) for x in line]

    # If it's a single integer
    if isinstance(line, int):
        return [line]

    # From here we expect a string
    if not isinstance(line, str):
        line = str(line)

    line = line.strip()
    if not line:
        return []

    # Try to evaluate as a Python literal (e.g., "[1,2]")
    try:
        val = ast.literal_eval(line)
        if isinstance(val, (list, tuple)):
            return [int(x) for x in val]
        # If eval gave a single number, treat it as one coin
        if isinstance(val, (int, float)):
            return [int(val)]
    except Exception:
        pass

    # Fallback: replace commas with spaces and split
    parts = line.replace(',', ' ').split()
    return [int(p) for p in parts]

