import sys

def canonical(word: str) -> str:
    i = 0
    n = len(word)
    out = []

    while i < n:
        ch = word[i]

        # ----- block of o / u -----
        if ch == 'o' or ch == 'u':
            total = 0
            while i < n and (word[i] == 'o' or word[i] == 'u'):
                total += 1 if word[i] == 'o' else 2
                i += 1
            if total % 2 == 0:
                out.append('u' * (total // 2))
            else:
                out.append('o' + 'u' * ((total - 1) // 2))
            continue

        # ----- block of k / h -----
        if ch == 'k' or ch == 'h':
            block = []
            while i < n and (word[i] == 'k' or word[i] == 'h'):
                block.append(word[i])
                i += 1
            cnt_h = block.count('h')
            if cnt_h == 0:                     # only k's
                out.append('k' * len(block))
            else:
                # count trailing k's after the last h
                trailing = 0
                for c in reversed(block):
                    if c == 'k':
                        trailing += 1
                    else:                     # c == 'h'
                        break
                out.append('h' * cnt_h + 'k' * trailing)
            continue

        # ----- any other character -----
        out.append(ch)
        i += 1

    return ''.join(out)


