def solve() -> None:
    data = list(map(int, sys.stdin.buffer.read().split()))
    if not data:
        return
    n, k = data[0], data[1]
    a = sorted(data[2:2 + n])

    def feasible(T: int) -> bool:
        dq = deque()
        dq.append(0)          # dp[0] is true
        L = 0
        for i in range(1, n + 1):
            # shrink left bound while range exceeds T
            while a[i - 1] - a[L] > T:
                L += 1
            # discard starts that are left of L
            while dq and dq[0] < L:
                dq.popleft()
            # need a start j with j <= i - k
            if dq and dq[0] <= i - k:
                if i == n:
                    return True
                dq.append(i)
        return False

    low, high = 0, a[-1] - a[0]
    while low < high:
        mid = (low + high) // 2
        if feasible(mid):
            high = mid
        else:
            low = mid + 1
    print(low)

